[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/dataset/minimal-discovery-001> ;
            sh:resultMessage "Recommended: identify at least one responsible party as the source authority for the dataset. Options include creator, editor, or publisher." ;
            sh:resultPath [ sh:alternativePath ( schema1:creator schema1:editor schema1:publisher ) ] ;
            sh:resultSeverity sh:Info ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape cdifd:responsiblePartyProperty ],
        [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/dataset/minimal-discovery-001> ;
            sh:resultMessage "Please provide a publication or release date, using ISO8601 format with at least a year and a month." ;
            sh:resultPath schema1:datePublished ;
            sh:resultSeverity sh:Info ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape cdifd:datePublishedProperty ] .

